# Token validation dependency
class OAuth2TokenValidator:
    """
    Dependency injection class for OAuth 2.0 bearer token validation.
    Validates tokens against Redis cache for high-performance lookups.
    """

    def __init__(self, required_scopes: Optional[list[str]] = None):
        self.required_scopes = required_scopes or []

    async def __call__(
        self,
        credentials: HTTPAuthorizationCredentials = Depends(bearer_scheme),
        redis_client: redis.Redis = Depends(get_redis),
    ) -> TokenData:
        token = credentials.credentials

        if not token:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Bearer token is missing",
                headers={"WWW-Authenticate": "Bearer"},
            )

        # Look up token in Redis
        try:
            token_json = await redis_client.get(f"oauth2:token:{token}")
        except redis.RedisError as e:
            raise HTTPException(
                status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
                detail=f"Token store unavailable: {str(e)}",
            )

        if token_json is None:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        try:
            token_data_dict = json.loads(token_json)
            token_data = TokenData(**token_data_dict)
        except (json.JSONDecodeError, ValueError) as e:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail=f"Corrupted token data: {str(e)}",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        # Check expiration
        expires_at = datetime.fromisoformat(token_data.expires_at)
        if datetime.utcnow() > expires_at:
            # Clean up expired token
            await redis_client.delete(f"oauth2:token:{token}")
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Token has expired",
                headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
            )

        # Check required scopes
        if self.required_scopes:
            missing_scopes = set(self.required_scopes) - set(token_data.scopes)
            if missing_scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scopes. Missing: {', '.join(missing_scopes)}",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope" scope="{" ".join(self.required_scopes)}"'
                    },
                )

        return token_data


# Pre-configured dependency instances
validate_token = OAuth2TokenValidator()
validate_token_read = OAuth2TokenValidator(required_scopes=["read"])
validate_token_write = OAuth2TokenValidator(required_scopes=["write"])
validate_token_admin = OAuth2TokenValidator(required_scopes=["admin"])


# Helper function to create and store tokens
async def create_token(
    redis_client: redis.Redis,
    user_id: str,
    email: str,
    scopes: list[str],
) -> tuple[str, TokenData]:
    token = secrets.token_urlsafe(48)
    now = datetime.utcnow()
    expires_at = now + timedelta(seconds=TOKEN_EXPIRY_SECONDS)

    token_data = TokenData(
        user_id=user_id,
        email=email,
        scopes=scopes,
        issued_at=now.isoformat(),
        expires_at=expires_at.isoformat(),
    )

    # Store in Redis with TTL
    await redis_client.setex(
        f"oauth2:token:{token}",
        TOKEN_EXPIRY_SECONDS,
        token_data.model_dump_json(),
    )

    # Also maintain a set of tokens per user for revocation
    await redis_client.sadd(f"oauth2:user_tokens:{user_id}", token)
    await redis_client.expire(f"oauth2:user_tokens:{user_id}", TOKEN_EXPIRY_SECONDS)

    return token, token_data


