@app.get("/health", response_model=HealthResponse, tags=["System"])
async def health_check():
    """Health check endpoint - no auth required."""
    redis_connected = False
    try:
        r = await get_redis()
        await r.ping()
        redis_connected = True
    except Exception:
        pass

    return HealthResponse(
        status="healthy" if redis_connected else "degraded",
        redis_connected=redis_connected,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.post("/auth/token", response_model=TokenResponse, tags=["Authentication"])
async def issue_token(
    user_id: str,
    email: str,
    scopes: str = "read,write",
    redis_client: redis.Redis = Depends(get_redis),
):
    """
    Issue a new OAuth 2.0 bearer token.
    In production, this would validate client credentials first.
    """
    scope_list = [s.strip() for s in scopes.split(",")]
    token, token_data = await create_token(redis_client, user_id, email, scope_list)

    return TokenResponse(
        access_token=token,
        expires_in=TOKEN_EXPIRY_SECONDS,
        user_id=user_id,
    )


@app.post("/auth/revoke", tags=["Authentication"])
async def revoke_token(
    token_data: TokenData = Depends(validate_token),
    credentials: HTTPAuthorizationCredentials = Depends(bearer_scheme),
    redis_client: redis.Redis = Depends(get_redis),
):
    """Revoke the current bearer token."""
    token = credentials.credentials
    await redis_client.delete(f"oauth2:token:{token}")
    await redis_client.srem(f"oauth2:user_tokens:{token_data.user_id}", token)

    return {"message": "Token revoked successfully"}


@app.post("/auth/revoke-all", tags=["Authentication"])
async def revoke_all_tokens(
    token_data: TokenData = Depends(validate_token),
    redis_client: redis.Redis = Depends(get_redis),
):
    """Revoke all tokens for the authenticated user."""
    user_tokens = await redis_client.smembers(f"oauth2:user_tokens:{token_data.user_id}")

    if user_tokens:
        pipe = redis_client.pipeline()
        for t in user_tokens:
            pipe.delete(f"oauth2:token:{t}")
        pipe.delete(f"oauth2:user_tokens:{token_data.user_id}")
        await pipe.execute()

    return {"message": f"Revoked {len(user_tokens)} token(s) for user {token_data.user_id}"}


