async def admin_stats(
    token_data: TokenData = Depends(validate_token_admin),
    redis_client: redis.Redis = Depends(get_redis),
):
    """Admin stats endpoint - requires 'admin' scope."""
    # Count active tokens in Redis
    cursor = 0
    token_count = 0
    while True:
        cursor, keys = await redis_client.scan(cursor, match="oauth2:token:*", count=100)
        token_count += len(keys)
        if cursor == 0:
            break

    return {
        "active_tokens": token_count,
        "requested_by": token_data.user_id,
        "timestamp": datetime.utcnow().isoformat(),
    }


